mapper.select:
SELECT id,user_id,nickname,content,contact,reply_content,reply_time,
status,create_time,is_deleted
FROM message

     AND user_id = #{userId} 
     AND nickname = #{nickname} 
     AND content LIKE CONCAT('%',#{content},'%') 
     AND status = #{status} 
    AND is_deleted = 0

ORDER BY create_time DESC

mapper.update:
UPDATE message
SET reply_content=#{replyContent}, reply_time=NOW(), status=1
WHERE id=#{id}
